INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Modernisation de la gestion des ressources humaines', 'Formation sur la digitalisation et optimisation des pratiques RH.', 5, 250000.00, 'entreprise', '2026-07-05', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre les enjeux de la digitalisation RH\n• Utiliser des outils modernes pour la gestion du personnel\n• Optimiser les processus RH\n• Améliorer la performance organisationnelle\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les participants à la modernisation de la gestion RH via la digitalisation et l’optimisation des pratiques.\n\n--- PRÉREQUIS ---\nConnaissances de base en gestion RH.\n\n--- CONTENU ---\nModule 1 : Introduction à la digitalisation RH\nModule 2 : Outils logiciels pour la gestion du personnel\nModule 3 : Optimisation des processus RH\nModule 4 : Mise en place d’un plan de modernisation\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nResponsables RH, managers, chefs d’entreprise.\n\n--- MÉTHODES ---\nCours interactifs, démonstrations, ateliers pratiques.\n\n--- SUPPORTS ---\nLogiciels RH, supports PDF.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
